using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Text;

namespace ePrint.ePrintUtilities
{
    internal class ePrintReportQueries
    {
        #region Estimates Query
        public string AllEstimatesByCustomerSelect = " SELECT DISTINCT      \r\n Replace(Replace(Replace(ISNULL(clnt.clientname,''),'%22','\\\"'),'%27%27',''''),'%27','''') AS [CompanyName],      \r\n CAST(  SUM(      dbo.fn_GetCostExMarkupValue(   c.EstimateItemID,   c.JobID,   jc.QtyNumber,   a.isConvertedToJob,   tpd.TotalcostExMarkup1,   tpd.TotalcostExMarkup2,   tpd.TotalcostExMarkup3,   tpd.TotalcostExMarkup4      )  ) OVER (PARTITION BY a.customerID) AS decimal(18,2)     ) AS CostExMarkup,      \r\n CAST(  SUM(      CASE         WHEN checkJob.isValidJob = 1 THEN       CASE ISNULL(jc.QTYNumber, 0)    WHEN 1 THEN ISNULL(tpd.TotalSubTotal1, 0)    WHEN 2 THEN ISNULL(tpd.TotalSubTotal2, 0)    WHEN 3 THEN ISNULL(tpd.TotalSubTotal3, 0)    WHEN 4 THEN ISNULL(tpd.TotalSubTotal4, 0)    ELSE ISNULL(tpd.TotalSubTotal1, 0)       END   ELSE ISNULL(tpd.TotalSubTotal1, 0)      END  )   \r\n OVER (PARTITION BY a.customerID)     AS decimal(18,2)     ) AS [TotalExTax],      CAST(  SUM(      CASE         WHEN checkJob.isValidJob = 1 THEN       CASE ISNULL(jc.QTYNumber, 0)    WHEN 1 THEN ISNULL(tpd.TotalSellingPrice1, 0)    WHEN 2 THEN ISNULL(tpd.TotalSellingPrice2, 0)    WHEN 3 THEN ISNULL(tpd.TotalSellingPrice3, 0)    WHEN 4 THEN ISNULL(tpd.TotalSellingPrice4, 0)    ELSE ISNULL(tpd.TotalSellingPrice1, 0)       END   ELSE ISNULL(tpd.TotalSellingPrice1, 0)      END  ) OVER (PARTITION BY a.customerID) AS decimal(18,2)     ) AS [TotalIncTax],      CAST(  ROUND(      (   SELECT        (CAST(ISNULL(SUM(est.EstimateSubTotal),0) AS DECIMAL(18, 2)) /         (    SELECT ISNULL(NULLIF(SUM(e.EstimateSubTotal), 0), 1)     FROM tb_Estimate e WITH (NOLOCK)     WHERE e.CustomerID = a.CustomerID      AND e.IsDeleted = 0       AND e.IsFromWebStore != 'yes'       AND Estimatenumber NOT IN ('Direct Invoice', 'DirectInvoice', 'Direct Job', 'DirectJob')       AND e.CompanyID = 2144        )       ) * 100   FROM tb_job jb    LEFT JOIN tb_Estimate est ON jb.EstimateID = est.EstimateID    WHERE est.IsDeleted = 0      AND est.CustomerID = a.CustomerID     AND est.IsFromWebStore != 'yes'      AND est.estimatenumber NOT IN ('Direct Invoice', 'DirectInvoice', 'Direct Job', 'DirectJob')      AND est.CompanyID = 2144      ), 0  ) AS INT     ) AS PercentageProgressedIntoJobs  FROM tb_estimate a  LEFT JOIN tb_client clnt ON clnt.clientID = a.customerID  LEFT JOIN tb_ClientReferencedBy r ON r.ReferencedID = clnt.referencedBy   LEFT JOIN tb_estimateitem c ON c.EstimateID = a.EstimateID AND c.isparentitem = 1   LEFT JOIN tb_Contact ct ON a.AttentionID = ct.ContactID      LEFT JOIN tb_accountingcode ac ON ac.AccountCodeID = c.AccountCodeID     LEFT JOIN tb_estimatestatus es ON es.statusid = a.statusid AND es.isdeleted = 0   LEFT JOIN tb_estimatestatus ess ON ess.statusid = c.EstimateItemStatusID     LEFT JOIN tb_costcenter cc ON cc.CostCentreID = a.CostCentreID    LEFT JOIN tb_esttotalpricedetails tpd ON tpd.EstimateID = a.estimateid      AND tpd.EstimateitemID = c.EstimateitemID      AND tpd.sectionid = CASE WHEN tpd.EstimateType IN ('B','K','N') THEN -999 ELSE 0 END    LEFT JOIN tb_companyaddress cnt ON cnt.AddressID = a.[Address]    LEFT JOIN tb_companyaddress Inv ON Inv.AddressID = a.InvoiceAddressID    LEFT JOIN tb_companyaddress da ON da.AddressID = a.DeliveryAddress    LEFT JOIN tb_companyaddress cus ON cus.AddressID = clnt.AddressID    LEFT JOIN tb_estitemdescription id ON id.Estimateitemid = c.Estimateitemid    LEFT JOIN tb_job j ON j.JOBID = c.JOBID   LEFT JOIN tb_user u ON u.userid = a.UserID AND u.IsDelete = 0    LEFT JOIN tb_user sp ON sp.UserID = a.SalesPerson AND sp.IsDelete = 0    LEFT JOIN tb_jobcard jc ON jc.estimateitemid = tpd.EstimateItemID    LEFT JOIN tb_user uu ON uu.userID = a.Salesperson  LEFT JOIN TrackingOption tr ON tr.Id = uu.TrackingOptionId   LEFT JOIN tb_estitemdescription esDescription ON esDescription.EstimateItemID = c.EstimateItemID    \r\n \r\n OUTER APPLY (  SELECT CASE        WHEN EXISTS (SELECT 1 FROM tb_job j WHERE j.JOBID = c.JOBID AND j.IsDeleted = 0)  \r\n OR EXISTS (SELECT 1 FROM tb_jobcard jc2 WHERE jc2.EstimateItemID = c.EstimateItemID AND a.isConvertedToJob = 0 AND isJobReverted = 1)       THEN 1        ELSE 0     END AS isValidJob ) checkJob ";
        public string AllEstimatesByCustomerWhere = " WHERE a.companyid = @companyid  \tAND isnull(a.IsFromWebStore,'no')='no'   \r\n\tAND a.EstimateNumber not LIKE '%direct%'   \r\n\tAND a.IsForInvoice=0   \r\n\tAND ISNULL(a.Iscompleted,0)=1   \r\n\tAND isnull(c.IsItemCompleted,0)=1 \r\n\tand Isnull(IsDirectJob,0)=0  \r\n\tAND clnt.Companytype = 'Customer'     \r\n\tAND clnt.IsDelete = 0 \r\n\tAND a.IsDeleted = 0      \r\n\tAND c.IsDeleted=0  ";
        public string AllEstimatesByCustomerGroupBy = "";//" GROUP BY \r\n    c.clientID,\r\n    c.clientName ";
        public string AllEstimatesByCustomerOrderBy = ""; //" ORDER BY CompanyName;  ";
        
        public StringBuilder GetAllEstimatesByCustomerSelectQuery()
        {
            StringBuilder estimatesByCustomer = new StringBuilder();
            estimatesByCustomer.Append(AllEstimatesByCustomerSelect);

            estimatesByCustomer.Append(AllEstimatesByCustomerWhere);
            estimatesByCustomer.Append(AllEstimatesByCustomerGroupBy);
            estimatesByCustomer.Append(AllEstimatesByCustomerOrderBy);

            return estimatesByCustomer;
        }
        #endregion

        #region Orders Query
        public string AllOrdersByCustomerSelect = "  SELECT DISTINCT Replace(Replace(Replace(ISNULL(clnt.clientname,''),'%22','\\\"'),'%27%27',''''),'%27','''') AS [CompanyName],    CAST(    SUM(  dbo.fn_GetCostExMarkupValue(  c.EstimateItemID,  c.JobID,  jc.QtyNumber,  a.isConvertedToJob,  tpd.TotalcostExMarkup1,  tpd.TotalcostExMarkup2,  tpd.TotalcostExMarkup3,  tpd.TotalcostExMarkup4  )    ) OVER (PARTITION BY a.customerID) AS decimal(18,2)    ) AS CostExMarkup,\r\n \r\n CAST(SUM(CASE WHEN checkJob.isValidJob = 1  or tpd.OrderItemShipping > 0 \r\n THEN CASE    WHEN tpd.OrderItemShipping > 0 THEN  ISNULL(tpd.TotalSubTotal1, 0) + ISNULL(oi.OrderItemShippingCostPriceIncMarkup, 0)  ELSE ISNULL(ISNULL(tpd.Totalsubtotal1, 0) + ISNULL(tpd.OrderItemShipping, 0), 0) END   \r\n ELSE ISNULL(ISNULL(tpd.Totalsubtotal1, 0) + ISNULL(tpd.OrderItemShipping, 0), 0)  END)   OVER (PARTITION BY a.customerID)AS decimal(18,2)) AS [TotalExTax],   \r\n CAST(SUM(CASE WHEN checkJob.isValidJob = 1 or tpd.OrderItemShipping > 0\r\n THEN CASE    WHEN tpd.OrderItemShipping > 0   THEN ISNULL(tpd.Totalsubtotal1, 0) + (ISNULL(oi.OrderItemShippingCostPriceIncMarkup, 0)) + ISNULL((tpd.TotalTaxPrice1), 0) + ISNULL((oi.OrderItemShippingTaxValue), 0)     \r\n ELSE ISNULL(tpd.Totalsubtotal1, 0) + ISNULL(tpd.TotalTaxPrice1, 0)   END    ELSE ISNULL(tpd.Totalsubtotal1, 0) + ISNULL(tpd.TotalTaxPrice1, 0)  END    )   OVER (PARTITION BY a.customerID) AS decimal(18,2)    ) AS [TotalIncTax], \r\n CAST(    ROUND(  (  SELECT  (CAST(ISNULL(SUM(est.EstimateSubTotal),0) AS DECIMAL(18, 2)) /  (    SELECT ISNULL(NULLIF(SUM(e.EstimateSubTotal), 0), 1) \r\n \r\n FROM tb_Estimate e WITH (NOLOCK) WHERE e.CustomerID = a.CustomerID  AND e.IsDeleted = 0   AND e.IsFromWebStore = 'yes'   AND Estimatenumber NOT IN ('Direct Invoice', 'DirectInvoice', 'Direct Job', 'DirectJob')   AND e.CompanyID = 2144  ) ) * 100  \r\n \r\n FROM tb_job jb   LEFT JOIN tb_Estimate est ON jb.EstimateID = est.EstimateID   WHERE est.IsDeleted = 0     AND est.CustomerID = a.CustomerID    AND est.IsFromWebStore = 'yes'     AND est.estimatenumber NOT IN ('Direct Invoice', 'DirectInvoice', 'Direct Job', 'DirectJob')     AND est.CompanyID = 2144  ), 0    ) AS INT    ) AS PercentageProgressedIntoJobs \r\n \r\n FROM tb_estimate a \r\n \r\n LEFT JOIN tb_client clnt ON clnt.clientID = a.customerID LEFT JOIN tb_ClientReferencedBy r ON r.ReferencedID = clnt.referencedBy  LEFT JOIN tb_estimateitem c ON c.EstimateID = a.EstimateID AND c.isparentitem = 1  LEFT JOIN tb_Contact ct ON a.AttentionID = ct.ContactID LEFT JOIN tb_accountingcode ac ON ac.AccountCodeID = c.AccountCodeID    LEFT JOIN tb_estimatestatus es ON es.statusid = a.statusid AND es.isdeleted = 0  LEFT JOIN tb_estimatestatus ess ON ess.statusid = c.EstimateItemStatusID    LEFT JOIN tb_costcenter cc ON cc.CostCentreID = a.CostCentreID   LEFT JOIN tb_esttotalpricedetails tpd ON tpd.EstimateID = a.estimateid AND tpd.EstimateitemID = c.EstimateitemID AND tpd.sectionid = CASE WHEN tpd.EstimateType IN ('B','K','N') THEN -999 ELSE 0 END   LEFT JOIN tb_companyaddress cnt ON cnt.AddressID = a.[Address]   LEFT JOIN tb_companyaddress Inv ON Inv.AddressID = a.InvoiceAddressID   LEFT JOIN tb_companyaddress da ON da.AddressID = a.DeliveryAddress   LEFT JOIN tb_companyaddress cus ON cus.AddressID = clnt.AddressID   LEFT JOIN tb_estitemdescription id ON id.Estimateitemid = c.Estimateitemid   LEFT JOIN tb_job j ON j.JOBID = c.JOBID  LEFT JOIN tb_user u ON u.userid = a.UserID AND u.IsDelete = 0   LEFT JOIN tb_user sp ON sp.UserID = a.SalesPerson AND sp.IsDelete = 0   LEFT JOIN tb_jobcard jc ON jc.estimateitemid = tpd.EstimateItemID   LEFT JOIN tb_user uu ON uu.userID = a.Salesperson LEFT JOIN TrackingOption tr ON tr.Id = uu.TrackingOptionId  LEFT JOIN tb_estitemdescription esDescription ON esDescription.EstimateItemID = c.EstimateItemID    LEFT JOIN tb_EstPriceCatalogue oi  ON oi.EstimateitemID = c.EstimateitemID      \r\n \r\n OUTER APPLY (    SELECT CASE    WHEN EXISTS (SELECT 1 FROM tb_job j WHERE j.JOBID = c.JOBID AND j.IsDeleted = 0) \r\n OR EXISTS (SELECT 1 FROM tb_jobcard jc2 WHERE jc2.EstimateItemID = c.EstimateItemID AND (a.isConvertedToJob = 0 AND isJobReverted = 0))   \r\n THEN 1  ELSE 0 END AS isValidJob) checkJob  ";
        public string AllOrdersByCustomerWhere = "  WHERE a.companyid = @companyid  and isnull(oi.ApproveStatus,0)<>2 \r\n   AND isnull(a.IsFromWebStore,'yes')='yes' \r\n   AND a.EstimateNumber not LIKE '%direct%' \r\n   AND a.IsForInvoice=0 \r\n   AND ISNULL(a.Iscompleted,0)=1 \r\n   AND isnull(c.IsItemCompleted,0)=1   \r\n   and Isnull(IsDirectJob,0)=0    \r\n   AND clnt.Companytype = 'Customer'   \r\n   and a.systemordernumber!=''\r\n   AND clnt.IsDelete = 0   \r\n   AND a.IsDeleted = 0    \r\n   AND c.IsDeleted=0  ";
        public string AllOrdersByCustomerGroupBy = ""; //" GROUP BY \r\n    c.clientID,\r\n    c.clientName ";
        public string AllOrdersByCustomerOrderBy = ""; //" \tORDER BY [CompanyName] ASC   ";

        public StringBuilder GetAllOrdersByCustomerSelectQuery()
        {
            StringBuilder estimatesByCustomer = new StringBuilder();
            estimatesByCustomer.Append(AllOrdersByCustomerSelect);

            estimatesByCustomer.Append(AllOrdersByCustomerWhere);
            estimatesByCustomer.Append(AllOrdersByCustomerGroupBy);
            estimatesByCustomer.Append(AllOrdersByCustomerOrderBy);

            return estimatesByCustomer;
        }
        #endregion

        #region Jobs Query
        public string AllJobsByCustomerSelect = "  SELECT Replace(Replace(Replace(Replace(LTRIM(ISNULL(d.ClientName,'')),'',''),'%22','\"'),'%27%27',''''),'%27%27','''') AS CompanyName,\r\n \r\n CAST(SUM( CASE  WHEN checkJob.isValidJob = 1 and b.IsFromWebStore ='no'\r\n THEN CASE ISNULL(jc.QTYNumber, 0)  \r\n WHEN 1 THEN ISNULL(tp.TotalSubTotal1, 0) \r\n WHEN 2 THEN ISNULL(tp.TotalSubTotal2, 0) \r\n WHEN 3 THEN ISNULL(tp.TotalSubTotal3, 0)  \r\n WHEN 4 THEN ISNULL(tp.TotalSubTotal4, 0)  \r\n ELSE ISNULL(tp.TotalSubTotal1, 0)   \r\n END ELSE ISNULL(tp.TotalSubTotal1, 0) + ISNULL(etp.OrderItemShippingCostPriceIncMarkup, 0)  END ) \r\n AS DECIMAL(18,2)) AS [TotalExcTax], \r\n \r\n CAST(SUM( CASE  WHEN checkJob.isValidJob = 1 and b.IsFromWebStore ='no'\r\n THEN CASE ISNULL(jc.QTYNumber, 0)  \r\n WHEN 1 THEN ISNULL(tp.TotalSellingPrice1, 0)  \r\n WHEN 2 THEN ISNULL(tp.TotalSellingPrice2, 0) \r\n WHEN 3 THEN ISNULL(tp.TotalSellingPrice3, 0)  \r\n WHEN 4 THEN ISNULL(tp.TotalSellingPrice4, 0)  \r\n ELSE ISNULL(tp.TotalSellingPrice1, 0)   END \r\n ELSE ISNULL(tp.Totalsubtotal1, 0)   + ISNULL(etp.OrderItemShippingCostPriceIncMarkup, 0) + ISNULL((tp.TotalTaxPrice1), 0) + ISNULL((etp.OrderItemShippingTaxValue), 0)\r\n END ) AS DECIMAL(18,2)) AS [TotalIncTax], \r\n\r\n CAST(SUM( CASE ISNULL(jc.QTYNumber, 0) \r\n WHEN 1 THEN ISNULL(tp.TotalcostExMarkup1, 0) \r\n WHEN 2 THEN ISNULL(tp.TotalcostExMarkup2, 0) \r\n WHEN 3 THEN ISNULL(tp.TotalcostExMarkup3, 0) \r\n WHEN 4 THEN ISNULL(tp.TotalcostExMarkup4, 0) \r\n ELSE ISNULL(tp.TotalcostExMarkup1, 0) END ) AS DECIMAL(18,2)) AS CostExMarkup,\r\n \r\n CAST(SUM( CASE  WHEN b.IsFromWebStore = 'no'    THEN CASE ISNULL(jc.QTYNumber, 0) WHEN 1 THEN ISNULL(tp.totalgrossprofitprice1, 0) WHEN 2 THEN ISNULL(tp.totalgrossprofitprice2, 0) WHEN 3 THEN ISNULL(tp.totalgrossprofitprice3, 0) WHEN 4 THEN ISNULL(tp.totalgrossprofitprice4, 0)END ELSE ISNULL(tp.totalgrossprofitprice1, 0) END ) AS DECIMAL(18,2)) AS GrossProfitPrice  \r\n\r\n,CAST(\r\n (\r\n CAST(\r\n SUM(\r\n  CASE \r\n  WHEN jc.QtyNumber = 1 THEN ISNULL(tp.TotalSubTotal1, 0) - ISNULL(tp.TotalCostExMarkup1, 0)\r\n  WHEN jc.QtyNumber = 2 THEN ISNULL(tp.TotalSubTotal2, 0) - ISNULL(tp.TotalCostExMarkup2, 0)\r\n  WHEN jc.QtyNumber = 3 THEN ISNULL(tp.TotalSubTotal3, 0) - ISNULL(tp.TotalCostExMarkup3, 0)\r\n  WHEN jc.QtyNumber = 4 THEN ISNULL(tp.TotalSubTotal4, 0) - ISNULL(tp.TotalCostExMarkup4, 0)\r\n  ELSE \r\n  CASE  \r\n   WHEN c.EstimateType = 'u' THEN tp.TotalGrossProfitPrice1 \r\n   ELSE isnull(tp.TotalSubTotal1, 0) - isnull(tp.TotalCostExMarkup1, 0)\r\n  END \r\n  END\r\n ) AS DECIMAL(18,2)\r\n )\r\n /\r\n NULLIF(\r\n CAST(\r\n  SUM(\r\n  CASE \r\n  WHEN jc.QtyNumber = 1 THEN ISNULL(tp.TotalSubTotal1, 0)\r\n  WHEN jc.QtyNumber = 2 THEN ISNULL(tp.TotalSubTotal2, 0)\r\n  WHEN jc.QtyNumber = 3 THEN ISNULL(tp.TotalSubTotal3, 0)\r\n  WHEN jc.QtyNumber = 4 THEN ISNULL(tp.TotalSubTotal4, 0)\r\n  ELSE ISNULL(tp.TotalSubTotal1, 0)\r\n  END\r\n  ) AS DECIMAL(18,2)\r\n ),0)\r\n ) * 100\r\nAS DECIMAL(18,2)) AS GrossProfitPercentage\r\n\r\n FROM tb_job a \r\n LEFT JOIN tb_estimate b ON b.EstimateID = a.EstimateID  \r\n LEFT JOIN tb_estimateitem c ON c.JOBID = a.JobID AND c.isparentitem = 1  \r\n LEFT JOIN tb_jobcard jc ON jc.estimateitemID = c.estimateitemID   \r\n LEFT JOIN tb_esttotalpricedetails tp ON tp.EstimateID = b.estimateid    AND tp.EstimateitemID = c.EstimateitemID    AND tp.sectionid = CASE WHEN tp.estimatetype IN('B','N','K') THEN -999 ELSE 0 END   \r\n left join tb_EstPriceCatalogue etp on etp.EstimateItemID=c.EstimateItemID and etp.QtyNumber=jc.QtyNumber  and etp.isdeleted=0  \r\n LEFT JOIN tb_Client d ON d.ClientID = b.CustomerID  \r\n\r\n OUTER APPLY ( SELECT  CASE  WHEN EXISTS (SELECT 1 FROM tb_job j WHERE j.JOBID = c.JOBID AND j.IsDeleted = 0)   OR EXISTS (SELECT 1 FROM tb_jobcard jc2 WHERE jc2.EstimateItemID = c.EstimateItemID   AND b.isConvertedToJob = 1   AND isJobReverted = 0) THEN 1 ELSE 0  END AS isValidJob) checkJob   ";
        public string AllJobsByCustomerWhere = " WHERE a.companyid = @companyid  AND a.IsDeleted = 0 AND b.IsDeleted = 0  AND b.IsForInvoice = 0  AND ISNULL(c.IsItemCompleted,0) = 1\r\n  AND a.IsReverted = 0\r\n  AND ISNULL(b.Iscompleted,0) = 1\r\n  AND c.IsDeleted = 0\r\n  AND a.jobnumber NOT IN ('DirectInvoice','Direct Invoice','0','-1')\r\n  AND ISNULL(jc.QTYNumber,0) > 0 and d.isDelete=0  ";
        public string AllJobsByCustomerGroupBy = "  GROUP BY Replace(Replace(Replace(Replace(LTRIM(ISNULL(d.ClientName,'')),'',''),'%22','\"'),'%27%27',''''),'%27%27','''') ";
        public string AllJobsByCustomerOrderBy = " ORDER BY [CompanyName] ASC   ";

        public StringBuilder GetAllJobsByCustomerSelectQuery()
        {
            StringBuilder queryByCustomer = new StringBuilder();
            queryByCustomer.Append(AllJobsByCustomerSelect);

            queryByCustomer.Append(AllJobsByCustomerWhere);
            queryByCustomer.Append(AllJobsByCustomerGroupBy);
            queryByCustomer.Append(AllJobsByCustomerOrderBy);

            return queryByCustomer;
        }
        #endregion

        #region Invoice By Customers Query
        public string AllInvoicesByCustomersSelect = "  SELECT   REPLACE(REPLACE(ISNULL(clnt.clientname, ''), '%27', ''''), '%22', '\"') AS ClientName, \r\n clnt.clientid,\r\n CAST(SUM( CASE  \r\n WHEN jc.QtyNumber = 1 THEN ISNULL(tp.TotalCostExMarkup1, 0)   \r\n WHEN jc.QtyNumber = 2 THEN ISNULL(tp.TotalCostExMarkup2, 0) \r\n WHEN jc.QtyNumber = 3 THEN ISNULL(tp.TotalCostExMarkup3, 0)     \r\n WHEN jc.QtyNumber = 4 THEN ISNULL(tp.TotalCostExMarkup4, 0)    \r\n ELSE ISNULL(tp.TotalGrossProfitPercentage1, 0)END) AS DECIMAL(18,2)    ) AS CostExMarkup,\r\n \r\n CAST(SUM(CASE WHEN j.HasJob = 1 OR jc2.HasJobCard = 1 \r\n THEN  \r\n CASE ISNULL(jc.QTYNumber, 0) \r\n\t WHEN 1 THEN ISNULL(tp.TotalSubTotal1, 0)  \r\n\t WHEN 2 THEN ISNULL(tp.TotalSubTotal2, 0)   \r\n\t WHEN 3 THEN ISNULL(tp.TotalSubTotal3, 0)    \r\n\t WHEN 4 THEN ISNULL(tp.TotalSubTotal4, 0)   \r\n ELSE ISNULL(tp.TotalSubTotal1, 0) END    \r\n ELSE ISNULL(tp.TotalSubTotal1, 0) + ISNULL(tp.OrderItemShipping, 0) END \r\n ) \r\n AS DECIMAL(18,2)) AS TotalExcTax,\r\n \r\n CAST(SUM(CASE     WHEN j.HasJob = 1 OR jc2.HasJobCard = 1 THEN  CASE ISNULL(jc.QTYNumber, 0)   \r\n WHEN 1 THEN ISNULL(tp.TotalSubTotal1, 0) + ISNULL(tp.TotalTaxPrice1 ,0) \r\n WHEN 2 THEN ISNULL(tp.TotalSubTotal2, 0) + ISNULL(tp.TotalTaxPrice2 ,0)\r\n WHEN 3 THEN ISNULL(tp.TotalSubTotal3, 0) + ISNULL(tp.TotalTaxPrice3 ,0)\r\n WHEN 4 THEN ISNULL(tp.TotalSubTotal4, 0) + ISNULL(tp.TotalTaxPrice4 ,0)\r\n ELSE ISNULL(tp.TotalSubTotal1, 0) + ISNULL(tp.TotalTaxPrice1 ,0) END    \r\n ELSE (ISNULL(etp.OrderItemShippingCostPriceIncMarkup, 0) + ISNULL((tp.TotalSubTotal1), 0) + ISNULL(tp.TotalTaxPrice1 ,0) + ISNULL(etp.OrderItemShippingTaxValue, 0)) \r\n \r\n END    ) AS DECIMAL(18,2)) AS TotalIncTax,  \r\n\r\nCAST( SUM(CASE     WHEN jc.QtyNumber = 1 THEN ISNULL(tp.TotalGrossProfitPrice1, 0)    WHEN jc.QtyNumber = 2 THEN ISNULL(tp.TotalGrossProfitPrice2, 0)    WHEN jc.QtyNumber = 3 THEN ISNULL(tp.TotalGrossProfitPrice3, 0)    WHEN jc.QtyNumber = 4 THEN ISNULL(tp.TotalGrossProfitPrice4, 0)    ELSE ISNULL(tp.TotalGrossProfitPrice1, 0)END ) AS DECIMAL(18,2)    ) AS GrossProfitPrice \r\n\r\n,CAST(    (        CAST(            SUM(                CASE                     WHEN jc.QtyNumber = 1 THEN ISNULL(tp.TotalSubTotal1, 0) - ISNULL(tp.TotalCostExMarkup1, 0)                    WHEN jc.QtyNumber = 2 THEN ISNULL(tp.TotalSubTotal2, 0) - ISNULL(tp.TotalCostExMarkup2, 0)                    WHEN jc.QtyNumber = 3 THEN ISNULL(tp.TotalSubTotal3, 0) - ISNULL(tp.TotalCostExMarkup3, 0)                    WHEN jc.QtyNumber = 4 THEN ISNULL(tp.TotalSubTotal4, 0) - ISNULL(tp.TotalCostExMarkup4, 0)                    ELSE                         CASE                              WHEN c.EstimateType = 'u' THEN tp.TotalGrossProfitPrice1                             ELSE ISNULL(tp.TotalmarkupPrice1, 0)                         END                 END            ) AS DECIMAL(18,2)        )        /        NULLIF(            CAST(                SUM(                    CASE                         WHEN jc.QtyNumber = 1 THEN ISNULL(tp.TotalSubTotal1, 0)                        WHEN jc.QtyNumber = 2 THEN ISNULL(tp.TotalSubTotal2, 0)                        WHEN jc.QtyNumber = 3 THEN ISNULL(tp.TotalSubTotal3, 0)                        WHEN jc.QtyNumber = 4 THEN ISNULL(tp.TotalSubTotal4, 0)                        ELSE ISNULL(tp.OrderItemShipping,0) + ISNULL(tp.TotalSubTotal1, 0)                    END                ) AS DECIMAL(18,2)            ),            0        )    ) * 100AS DECIMAL(18,2)) AS GrossProfitPercentage    \r\n\r\nFROM tb_Invoice a  \r\nLEFT JOIN tb_client clnt ON clnt.clientID = a.clientID  \r\nLEFT JOIN tb_estimateitem c ON c.InvoiceID = a.InvoiceID AND c.isparentitem = 1  \r\nLEFT JOIN tb_EstTotalPriceDetails tp ON tp.EstimateitemID = c.EstimateitemID    AND tp.sectionid = CASE WHEN tp.estimatetype IN ('B','N','K')  THEN -999 ELSE 0 END  \r\nLEFT JOIN tb_jobcard jc ON jc.estimateitemid = tp.estimateitemid  \r\nLEFT JOIN tb_Estimate b ON b.EstimateID = c.EstimateID OR b.EstimateID = a.EstimateID  \r\nleft join tb_EstPriceCatalogue etp on etp.EstimateItemID=c.estimateitemID and etp.QtyNumber=jc.QtyNumber   \r\nleft join tb_pricecatalogue pc on pc.pricecatalogueid=etp.pricecatalogueid \r\nOUTER APPLY (SELECT TOP 1 1 AS HasJob  FROM tb_job WHERE JOBID = c.JOBID AND IsDeleted = 0) j \r\nOUTER APPLY (SELECT TOP 1 1 AS HasJobCard FROM tb_jobcard jc2  WHERE jc2.EstimateItemID = c.EstimateItemID AND b.isConvertedToJob = 1 AND \r\nisJobReverted = 0) jc2   ";
        public string AllInvoicesByCustomersWhere = " WHERE \r\n    a.CompanyID = @companyid  AND a.IsDeleted = 0\r\n    AND c.IsDeleted = 0\r\n    AND ISNULL(c.IsItemCompleted, 0) = 1\r\n    AND a.InvoiceNumber != '0'  and clnt.isDelete=0   ";
        public string AllInvoicesByCustomersGroupBy = " GROUP BY \r\n    clnt.clientID,REPLACE(REPLACE(ISNULL(clnt.clientname, ''), '%27', ''''), '%22', '\"') ";
        public string AllInvoicesByCustomersOrderBy = " ORDER BY \r\n    ClientName;   ";
        
        public StringBuilder GetAllInvoicesByCustomersSelectQuery()
        {
            StringBuilder queryByCustomer = new StringBuilder();
            queryByCustomer.Append(AllInvoicesByCustomersSelect);

            queryByCustomer.Append(AllInvoicesByCustomersWhere);
            queryByCustomer.Append(AllInvoicesByCustomersGroupBy);
            queryByCustomer.Append(AllInvoicesByCustomersOrderBy);

            return queryByCustomer;
        }
        #endregion

        #region Invoice By Accounting Code Query
        public string AllInvoicesByAccountingCodeSelect = " SELECT \r\n    ac.Code as AccountingCode,\r\n\r\n    CAST(SUM(\r\n        CASE \r\n            WHEN jc.QtyNumber = 1 THEN ISNULL(tp.TotalCostExMarkup1, 0)\r\n            WHEN jc.QtyNumber = 2 THEN ISNULL(tp.TotalCostExMarkup2, 0)\r\n            WHEN jc.QtyNumber = 3 THEN ISNULL(tp.TotalCostExMarkup3, 0)\r\n            WHEN jc.QtyNumber = 4 THEN ISNULL(tp.TotalCostExMarkup4, 0)\r\n            ELSE ISNULL(tp.TotalCostExMarkup1, 0)\r\n        END\r\n    ) AS DECIMAL(18,2)) AS CostExMarkup,\r\n\r\n    CAST(SUM(\r\n        CASE \r\n            WHEN j.HasJob = 1 OR jc2.HasJobCard = 1 THEN\r\n                CASE ISNULL(jc.QTYNumber, 0)\r\n                    WHEN 1 THEN ISNULL(tp.TotalSubTotal1, 0)\r\n                    WHEN 2 THEN ISNULL(tp.TotalSubTotal2, 0)\r\n                    WHEN 3 THEN ISNULL(tp.TotalSubTotal3, 0)\r\n                    WHEN 4 THEN ISNULL(tp.TotalSubTotal4, 0)\r\n                    ELSE ISNULL(tp.TotalSubTotal1, 0)\r\n                END\r\n            ELSE ISNULL(tp.TotalSubTotal1, 0)\r\n        END\r\n    ) AS DECIMAL(18,2)) AS TotalExcTax,\r\n\r\n    CAST(SUM(\r\n        CASE \r\n            WHEN j.HasJob = 1 OR jc2.HasJobCard = 1 THEN\r\n                CASE ISNULL(jc.QTYNumber, 0)\r\n                    WHEN 1 THEN ISNULL(tp.TotalSellingPrice1, 0)\r\n                    WHEN 2 THEN ISNULL(tp.TotalSellingPrice2, 0)\r\n                    WHEN 3 THEN ISNULL(tp.TotalSellingPrice3, 0)\r\n                    WHEN 4 THEN ISNULL(tp.TotalSellingPrice4, 0)\r\n                    ELSE ISNULL(tp.TotalSellingPrice1, 0)\r\n                END\r\n            ELSE ISNULL(tp.TotalSellingPrice1, 0)\r\n        END\r\n    ) AS DECIMAL(18,2)) AS TotalIncTax,\r\n\r\n    CAST(SUM(\r\n        CASE \r\n            WHEN jc.QtyNumber = 1 THEN ISNULL(tp.TotalGrossProfitPrice1, 0)\r\n            WHEN jc.QtyNumber = 2 THEN ISNULL(tp.TotalGrossProfitPrice2, 0)\r\n            WHEN jc.QtyNumber = 3 THEN ISNULL(tp.TotalGrossProfitPrice3, 0)\r\n            WHEN jc.QtyNumber = 4 THEN ISNULL(tp.TotalGrossProfitPrice4, 0)\r\n            ELSE ISNULL(tp.TotalGrossProfitPrice1, 0)\r\n        END\r\n    ) AS DECIMAL(18,2)) AS GrossProfitPrice,\r\n\r\n    CAST(\r\n        CASE \r\n            WHEN SUM(\r\n                CASE \r\n                    WHEN j.HasJob = 1 OR jc2.HasJobCard = 1 THEN\r\n                        CASE ISNULL(jc.QTYNumber, 0)\r\n                            WHEN 1 THEN ISNULL(tp.TotalSubTotal1, 0)\r\n                            WHEN 2 THEN ISNULL(tp.TotalSubTotal2, 0)\r\n                            WHEN 3 THEN ISNULL(tp.TotalSubTotal3, 0)\r\n                            WHEN 4 THEN ISNULL(tp.TotalSubTotal4, 0)\r\n                            ELSE ISNULL(tp.TotalSubTotal1, 0)\r\n                        END\r\n                    ELSE ISNULL(tp.TotalSubTotal1, 0)\r\n                END\r\n            ) = 0 THEN 0\r\n            ELSE \r\n                ROUND(\r\n                    SUM(\r\n                        CASE \r\n                            WHEN jc.QtyNumber = 1 THEN ISNULL(tp.TotalGrossProfitPrice1, 0)\r\n                            WHEN jc.QtyNumber = 2 THEN ISNULL(tp.TotalGrossProfitPrice2, 0)\r\n                            WHEN jc.QtyNumber = 3 THEN ISNULL(tp.TotalGrossProfitPrice3, 0)\r\n                            WHEN jc.QtyNumber = 4 THEN ISNULL(tp.TotalGrossProfitPrice4, 0)\r\n                            ELSE ISNULL(tp.TotalGrossProfitPrice1, 0)\r\n                        END\r\n                    ) \r\n                    / \r\n                    SUM(\r\n                        CASE \r\n                            WHEN j.HasJob = 1 OR jc2.HasJobCard = 1 THEN\r\n                                CASE ISNULL(jc.QTYNumber, 0)\r\n                                    WHEN 1 THEN ISNULL(tp.TotalSubTotal1, 0)\r\n                                    WHEN 2 THEN ISNULL(tp.TotalSubTotal2, 0)\r\n                                    WHEN 3 THEN ISNULL(tp.TotalSubTotal3, 0)\r\n                                    WHEN 4 THEN ISNULL(tp.TotalSubTotal4, 0)\r\n                                    ELSE ISNULL(tp.TotalSubTotal1, 0)\r\n                                END\r\n                            ELSE ISNULL(tp.TotalSubTotal1, 0)\r\n                        END\r\n                    ) * 100, 2\r\n                )\r\n        END AS DECIMAL(18,2)\r\n    ) AS GrossProfitPercentage\r\n\r\nFROM tb_Invoice a\r\nLEFT JOIN tb_client clnt ON clnt.clientID = a.clientID\r\nLEFT JOIN tb_estimateitem c \r\n    ON c.InvoiceID = a.InvoiceID \r\n   AND c.isparentitem = 1\r\nLEFT JOIN tb_EstTotalPriceDetails tp \r\n    ON tp.EstimateitemID = c.EstimateitemID \r\n   AND tp.sectionid = CASE WHEN tp.estimatetype IN ('B','N','K') THEN -999 ELSE 0 END\r\nLEFT JOIN tb_jobcard jc \r\n    ON jc.estimateitemid = tp.estimateitemid\r\nLEFT JOIN tb_Estimate b \r\n    ON b.EstimateID = c.EstimateID OR b.EstimateID = a.EstimateID\r\nLEFT JOIN tb_AccountingCode ac \r\n    ON ac.AccountCodeID = c.AccountCodeID\r\n\r\n-- Precompute job existence flags\r\nOUTER APPLY (\r\n    SELECT TOP 1 1 AS HasJob \r\n    FROM tb_job \r\n    WHERE JOBID = c.JOBID AND IsDeleted = 0\r\n) j\r\nOUTER APPLY (\r\n    SELECT TOP 1 1 AS HasJobCard \r\n    FROM tb_jobcard jc2 \r\n    WHERE jc2.EstimateItemID = c.EstimateItemID \r\n      AND b.isConvertedToJob = 1 \r\n      AND isJobReverted = 0\r\n) jc2 ";
        public string AllInvoicesByAccountingCodeWhere = " WHERE \r\n    a.CompanyID = @companyid \r\n   and isnull(b.IsFromWebStore,'no')='no'  AND a.IsDeleted = 0\r\n    AND c.IsDeleted = 0\r\n    AND ISNULL(c.IsItemCompleted, 0) = 1\r\n    AND a.InvoiceNumber != '0'  and ac.IsDeleted=0 ";
        public string AllInvoicesByAccountingCodeGroupBy = " GROUP BY \r\n    ac.Code ";
        public string AllInvoicesByAccountingCodeOrderBy = " ORDER BY \r\n    ac.Code;  ";

        public StringBuilder GetAllInvoicesByAccountingCodeSelectQuery()
        {
            StringBuilder queryByCustomer = new StringBuilder();
            queryByCustomer.Append(AllInvoicesByAccountingCodeSelect);

            queryByCustomer.Append(AllInvoicesByAccountingCodeWhere);
            queryByCustomer.Append(AllInvoicesByAccountingCodeGroupBy);
            queryByCustomer.Append(AllInvoicesByAccountingCodeOrderBy);

            return queryByCustomer;
        }
        #endregion
    }
